// Comparison pages: /vs/<category-slug>/<pair-slug>/
// Each entry produces a head-to-head SEO page for two related tools.
// Target queries like "CHA2DS2-VASc vs CHADS2", "Wells DVT vs Padua".
//
// URL structure: /vs/{category}/{pair-slug}/ — mirrors the site IA
// so each hub also has its own comparison index at /vs/{category}/.

export interface ComparePair {
  slug: string            // URL path segment under /vs/{categorySlug}/
  toolA: string           // tool slug (must exist in tools.ts)
  toolB: string           // tool slug (must exist in tools.ts)
  title: string           // e.g. "CHA2DS2-VASc vs CHADS2"
  metaTitle: string       // <title> — include "| maratool"
  metaDescription: string // 140-160 chars
  category: 'Health' | 'Developer' | 'Text' | 'Image' | 'Color' | 'Converter' | 'PDF' | 'Marketing' | 'Mockup'
  intro: string           // HTML paragraph(s) introducing the comparison
  whenToUseA: string      // HTML paragraph(s) "Use A when..."
  whenToUseB: string      // HTML paragraph(s) "Use B when..."
  // Side-by-side comparison table rows: [feature, valueA, valueB]
  comparison: Array<{ feature: string; a: string; b: string }>
  // Optional bottom-line summary
  bottomLine: string
  faq: Array<{ q: string; a: string }>
}

export function categorySlug(category: ComparePair['category']): string {
  return category.toLowerCase()
}

